command:
// =========================
// DUNGEON LEVEL GENERATOR v2
// Room Purpose + Room Details
// =========================

function roll(sides) {
    return Math.ceil(Math.random() * sides);
}

function pick(table) {
    const r = roll(table.length);
    return { roll: r, result: table[r - 1] };
}

const roomPurposeTable = [
    { name: "Combat", description: "Danger, enemies, ambushes, guards, monsters, or hostile creatures." },
{ name: "Cache", description: "Treasure, supplies, equipment, clues, or useful rewards." },
{ name: "Sidekick", description: "An ally, prisoner, guide, rescued NPC, or helpful creature." },
{ name: "Offshoot", description: "Optional side path, hidden area, shortcut, or risky detour." },
{ name: "Foreshadowing", description: "A clue, omen, warning, remains, tracks, or signs of future danger." },
{ name: "History", description: "Lore about the dungeon, its builders, former inhabitants, disaster, religion, or purpose." },
{ name: "Oddity", description: "A strange, memorable, magical, creepy, or unexplained feature." },
{ name: "Forge", description: "Crafting, repair, upgrades, enchanting, restoring, or modifying gear." },
{ name: "Factions", description: "Social or political scene involving rival groups, scouts, negotiations, or disputes." },
{ name: "Map", description: "Directions, secret passages, nearby rooms, future locations, or world clues." },
{ name: "Puzzle", description: "An obstacle requiring observation, interaction, experimentation, or problem-solving." }
];

const detailTables = {
    Combat: {
        main: ["Guard post", "Ambush", "Wandering monster", "Boss/miniboss", "Territorial beasts", "Rival explorers"],
        twist: ["Poor lighting", "Difficult terrain", "Hazard nearby", "Enemies distracted", "Reinforcements possible", "Enemy morale is shaky"]
    },
    Cache: {
        main: ["Coins/valuables", "Useful supplies", "Weapons/armor", "Map/clue", "Trade goods", "Potion/consumable"],
        twist: ["Hidden", "Locked", "Trapped", "Guarded", "Damaged", "Clearly stolen"]
    },
    Sidekick: {
        main: ["Prisoner", "Lost adventurer", "Wounded scout", "Local guide", "Strange creature", "Defector"],
        twist: ["Afraid", "Injured", "Knows a secret", "Being hunted", "Not fully honest", "Has useful skills"]
    },
    Offshoot: {
        main: ["Hidden side room", "Collapsed passage", "Shortcut", "Vertical shaft", "Secret tunnel", "Optional danger room"],
        twist: ["Hard to notice", "Requires tools", "One-way path", "Partially flooded", "Unstable", "Leads near a major threat"]
    },
    Foreshadowing: {
        main: ["Claw marks", "Old warning", "Corpse", "Strange symbol", "Distant sound", "Abandoned gear"],
        twist: ["Points to boss", "Warns of trap", "Hints at faction", "Reveals monster weakness", "Shows past disaster", "Misleading clue"]
    },
    History: {
        main: ["Mural", "Inscription", "Old journal", "Statue", "Tomb carving", "Broken relic"],
        twist: ["Names the builders", "Explains the dungeon purpose", "Shows betrayal", "Mentions a lost treasure", "Warns of a curse", "Connects to a faction"]
    },
    Oddity: {
        main: [
            "Whispering wall",
            "Floating object",
            "Impossible shadow",
            "Room colder than it should be",
            "Living stone",
            "Repeating vision",
            "Ancient shrine",
            "Portal room",
            "Collapsed wonder",
            "Ritual chamber",
            "Secret garden",
            "Artifact display"
        ],
        twist: [
            "Harmless but strange",
            "Minor magical effect",
            "Useful clue",
            "Tempts interaction",
            "Changes when observed",
            "Attracts monsters",
            "Magically protected",
            "Recently disturbed",
            "Haunted",
            "Still active",
            "Partially destroyed",
            "Hidden"
        ]
    },
    Forge: {
        main: ["Blacksmith forge", "Alchemy bench", "Enchanting circle", "Repair station", "Ancient machine", "Crafting supplies"],
        twist: ["Still usable", "Needs fuel", "Requires rare component", "Dangerous malfunction", "Can upgrade gear", "Someone already uses it"]
    },
    Factions: {
        main: ["Faction guards", "Negotiation scene", "Prisoner exchange", "Faction shrine", "Spy meeting", "Internal argument"],
        twist: ["Can be bargained with", "Hostile on sight", "Rival faction nearby", "One member defects", "They want help", "They are hiding something"]
    },
    Map: {
        main: ["Dungeon map", "Regional map", "Secret passage clue", "Treasure route", "Faction territory map", "Warning diagram"],
        twist: ["Incomplete", "Outdated", "Encoded", "Trapped", "Shows hidden entrance", "Points to another hex"]
    },
    Puzzle: {
        main: ["Lever puzzle", "Riddle door", "Pressure plates", "Symbol sequence", "Rotating room", "Light/mirror puzzle"],
        twist: ["Failure causes damage", "Failure summons enemy", "Timed challenge", "Multiple solutions", "Clue nearby", "Bypass possible at a cost"]
    }
};

const conditionTable = [
    "Pristine / untouched",
"Dusty but usable",
"Damaged",
"Partially collapsed",
"Recently disturbed",
"Actively in use"
];

const sensoryTable = [
    "Cold air",
"Damp smell",
"Old blood",
"Burnt scent",
"Whispers or echoes",
"Scratching sounds",
"Faint light",
"Rotten smell",
"Heavy silence",
"Strange vibration"
];

const roomCount = await Dialog.prompt({
    title: "Dungeon Level Generator v2",
    content: `
    <p>How many rooms are on this dungeon level?</p>
    <input id="rooms" type="number" value="5" min="1" max="50"/>
    `,
    callback: html => Number(html.find("#rooms").val())
});

let rooms = [];
let previousPurpose = null;

for (let i = 1; i <= roomCount; i++) {
    let purposeRoll;
    let purpose;
    let attempts = 0;

    do {
        purposeRoll = roll(11);
        purpose = roomPurposeTable[purposeRoll - 1];
        attempts++;
    } while (
        previousPurpose &&
        purpose.name === previousPurpose &&
        purpose.name !== "Combat" &&
        purpose.name !== "Oddity" &&
        attempts < 20
    );

    const main = pick(detailTables[purpose.name].main);
    const twist = pick(detailTables[purpose.name].twist);
    const condition = pick(conditionTable);
    const sensory = pick(sensoryTable);

    rooms.push({
        number: i,
        purposeRoll,
        purpose: purpose.name,
        description: purpose.description,
        main,
        twist,
        condition,
        sensory
    });

    previousPurpose = purpose.name;
}

let output = `
<h2>Dungeon Level Generator v2</h2>

<p><b>Room Count:</b> ${roomCount}</p>
<p><i>Back-to-back repeats are prevented except for Combat and Oddity.</i></p>

<hr>

<h3>Rooms</h3>

<ol>
${rooms.map(room => `
    <li>
    <h4>Room ${room.number}: ${room.purpose}</h4>

    <p><b>Purpose Roll:</b> d11 = ${room.purposeRoll}</p>
    <p><b>Purpose:</b> ${room.purpose}</p>
    <p><i>${room.description}</i></p>

    <p><b>${room.purpose} Detail Roll:</b> d${detailTables[room.purpose].main.length} = ${room.main.roll}</p>
    <p><b>Main Detail:</b> ${room.main.result}</p>

    <p><b>Twist Roll:</b> d${detailTables[room.purpose].twist.length} = ${room.twist.roll}</p>
    <p><b>Twist:</b> ${room.twist.result}</p>

    <p><b>Condition Roll:</b> d6 = ${room.condition.roll}</p>
    <p><b>Condition:</b> ${room.condition.result}</p>

    <p><b>Sensory Roll:</b> d10 = ${room.sensory.roll}</p>
    <p><b>Sensory Detail:</b> ${room.sensory.result}</p>

    <p><b>Summary:</b> This is a <b>${room.purpose.toLowerCase()}</b> room featuring
    <b>${room.main.result.toLowerCase()}</b>. The twist is
    <b>${room.twist.result.toLowerCase()}</b>. The room is
    <b>${room.condition.result.toLowerCase()}</b>, with
    <b>${room.sensory.result.toLowerCase()}</b>.</p>
    </li>
    <br>
    `).join("")}
    </ol>

    <hr>

    <h3>Quick Level Summary</h3>

    <ul>
    ${rooms.map(room => `
        <li>
        <b>Room ${room.number}:</b> ${room.purpose} —
        ${room.main.result}; ${room.twist.result}
        </li>
        `).join("")}
        </ul>
        `;

        ChatMessage.create({
            speaker: ChatMessage.getSpeaker(),
                           content: output
        });
